30→func (s *DockerHubSource) FetchNewReleases(ctx context.Context) ([]IngestionResult, error) {
31→	url := fmt.Sprintf("%s/v2/repositories/%s/tags/?page_size=25&ordering=last_updated",
32→		s.baseURL, s.repository)
33→
34→	req, err := http.NewRequestWithContext(ctx, http.MethodGet, url, nil)
35→	if err != nil {
36→		return nil, fmt.Errorf("create request: %w", err)
37→	}
38→
39→	resp, err := s.client.Do(req)
40→	if err != nil {
41→		return nil, fmt.Errorf("fetch tags: %w", err)
42→	}
43→	defer resp.Body.Close()
44→
45→	if resp.StatusCode != http.StatusOK {
46→		return nil, fmt.Errorf("unexpected status: %d", resp.StatusCode)
47→	}
48→
49→	var body struct {
50→		Results []struct {
51→			Name        string `json:"name"`
52→			LastUpdated string `json:"last_updated"`
53→		} `json:"results"`
54→	}
55→	if err := json.NewDecoder(resp.Body).Decode(&body); err != nil {
56→		return nil, fmt.Errorf("decode response: %w", err)
57→	}
58→
59→	results := make([]IngestionResult, 0, len(body.Results))
60→	for _, tag := range body.Results {
61→		ts, _ := time.Parse(time.RFC3339Nano, tag.LastUpdated)
62→		results = append(results, IngestionResult{
63→			Repository: s.repository,
64→			RawVersion: tag.Name,
65→			Timestamp:  ts,
66→		})
67→	}
68→	return results, nil
69→}
